import { mutationGeneric, queryGeneric } from 'convex/server';
import { v } from 'convex/values';

// Capability-run persistence. Shape mirrors lib/store/runs CapabilityRunRecord
// so the client wrapper can pass Convex documents through untouched.
//
// Uses the *Generic builders because convex/_generated is not committed — it
// is regenerated by `npx convex dev` at provisioning time. The loss in type
// precision is acceptable for the log: payloads match the schema validators.

const MAX_RUNS = 50;
const MAX_PERSISTED_REF_CHARS = 200_000;

const STEP_VALIDATOR = v.union(
  v.literal('prepared'),
  v.literal('sending'),
  v.literal('awaiting'),
  v.literal('received'),
  v.literal('parsing'),
  v.literal('placing'),
  v.literal('done')
);

const STATUS_VALIDATOR = v.union(v.literal('running'), v.literal('ok'), v.literal('error'));
const ARTIFACT_KIND_VALIDATOR = v.union(
  v.literal('image'),
  v.literal('video'),
  v.literal('audio'),
  v.literal('spatial')
);
const SCOPE_VALIDATOR = v.union(v.literal('workspace'), v.literal('team'));

interface RunDoc {
  _id: unknown;
  clientRunId: string;
  tool: string;
  provider: string;
  model: string;
  prompt: string;
  step?: string;
  rewrittenPrompt?: string;
  rationale?: string;
  aspectRatio?: string;
  imageUrl?: string;
  latencyMs?: number;
  inputs?: unknown;
  outputs?: unknown;
  status: 'running' | 'ok' | 'error';
  startedAt: number;
  finishedAt?: number;
  error?: string;
  httpStatus?: number;
  definitionId?: string;
  entryRef?: unknown;
  artifactKind?: string;
  outputRefs?: string[];
  scope?: string;
  publishedVersion?: number;
}

function toRecord(doc: RunDoc) {
  return {
    id: doc.clientRunId,
    tool: doc.tool,
    provider: doc.provider,
    model: doc.model,
    prompt: doc.prompt,
    rewrittenPrompt: doc.rewrittenPrompt,
    rationale: doc.rationale,
    aspectRatio: doc.aspectRatio,
    imageUrl: doc.imageUrl,
    latencyMs: doc.latencyMs,
    status: doc.status,
    step: doc.step,
    startedAt: doc.startedAt,
    finishedAt: doc.finishedAt,
    error: doc.error,
    httpStatus: doc.httpStatus,
    definitionId: doc.definitionId,
    entryRef: doc.entryRef,
    inputs: doc.inputs,
    artifactKind: doc.artifactKind,
    outputRefs: doc.outputRefs,
    scope: doc.scope,
    publishedVersion: doc.publishedVersion,
  };
}

function toPersistableRef(value: string | undefined): string | undefined {
  if (!value) return undefined;
  if (value.startsWith('data:')) return undefined;
  if (value.length > MAX_PERSISTED_REF_CHARS) return undefined;
  return value;
}

function toPersistableRefs(values: string[] | undefined): string[] | undefined {
  if (!values) return undefined;
  const refs = values.flatMap((value) => {
    const ref = toPersistableRef(value);
    return ref ? [ref] : [];
  });
  return refs.length > 0 ? refs : undefined;
}

export const list = queryGeneric({
  args: { wsId: v.optional(v.id('workspace')) },
  handler: async (ctx, args) => {
    const docs: RunDoc[] = args.wsId
      ? ((await ctx.db
          .query('capabilityRun')
          .withIndex('by_ws', (q: any) => q.eq('wsId', args.wsId))
          .order('desc')
          .take(MAX_RUNS)) as RunDoc[])
      : ((await ctx.db.query('capabilityRun').order('desc').take(MAX_RUNS)) as RunDoc[]);
    return docs.map(toRecord);
  },
});

async function findByClientId(ctx: any, clientRunId: string): Promise<RunDoc | null> {
  return (await ctx.db
    .query('capabilityRun')
    .withIndex('by_client_run_id', (q: any) => q.eq('clientRunId', clientRunId))
    .unique()) as RunDoc | null;
}

export const start = mutationGeneric({
  args: {
    clientRunId: v.string(),
    wsId: v.optional(v.id('workspace')),
    tool: v.string(),
    provider: v.string(),
    model: v.string(),
    prompt: v.string(),
    aspectRatio: v.optional(v.string()),
    inputs: v.optional(v.any()),
    artifactKind: v.optional(ARTIFACT_KIND_VALIDATOR),
    scope: v.optional(SCOPE_VALIDATOR),
    startedAt: v.number(),
  },
  handler: async (ctx, args) => {
    const existing = await findByClientId(ctx, args.clientRunId);
    if (existing) return args.clientRunId;
    await ctx.db.insert('capabilityRun', {
      clientRunId: args.clientRunId,
      wsId: args.wsId,
      tool: args.tool,
      provider: args.provider,
      model: args.model,
      prompt: args.prompt,
      aspectRatio: args.aspectRatio,
      inputs:
        args.inputs ?? { prompt: args.prompt, model: args.model, aspectRatio: args.aspectRatio },
      outputs: {},
      artifactKind: args.artifactKind,
      scope: args.scope,
      startedAt: args.startedAt,
      status: 'running',
    });
    return args.clientRunId;
  },
});

export const step = mutationGeneric({
  args: { clientRunId: v.string(), step: STEP_VALIDATOR },
  handler: async (ctx, args) => {
    const doc = await findByClientId(ctx, args.clientRunId);
    if (!doc) return;
    await ctx.db.patch(doc._id as any, { step: args.step });
  },
});

export const finish = mutationGeneric({
  args: {
    clientRunId: v.string(),
    status: v.optional(STATUS_VALIDATOR),
    provider: v.optional(v.string()),
    model: v.optional(v.string()),
    rewrittenPrompt: v.optional(v.string()),
    rationale: v.optional(v.string()),
    aspectRatio: v.optional(v.string()),
    imageUrl: v.optional(v.string()),
    latencyMs: v.optional(v.number()),
    error: v.optional(v.string()),
    httpStatus: v.optional(v.number()),
    inputs: v.optional(v.any()),
    artifactKind: v.optional(ARTIFACT_KIND_VALIDATOR),
    outputRefs: v.optional(v.array(v.string())),
    scope: v.optional(SCOPE_VALIDATOR),
    finishedAt: v.number(),
  },
  handler: async (ctx, args) => {
    const doc = await findByClientId(ctx, args.clientRunId);
    if (!doc) return;
    const {
      clientRunId: _ignored,
      imageUrl: _imageUrl,
      outputRefs: _outputRefs,
      ...patch
    } = args;
    const existingOutputs =
      typeof doc.outputs === 'object' && doc.outputs !== null
        ? (doc.outputs as Record<string, unknown>)
        : {};
    const nextImageUrl =
      toPersistableRef(args.imageUrl) ?? toPersistableRef(doc.imageUrl);
    const nextOutputRefs =
      toPersistableRefs(args.outputRefs) ?? toPersistableRefs(doc.outputRefs);
    const nextOutputs: Record<string, unknown> = {
      ...existingOutputs,
      latencyMs: args.latencyMs ?? doc.latencyMs,
    };
    if (nextImageUrl) nextOutputs.imageUrl = nextImageUrl;
    else delete nextOutputs.imageUrl;
    if (nextOutputRefs) nextOutputs.outputRefs = nextOutputRefs;
    else delete nextOutputs.outputRefs;

    const topLevelPatch: Record<string, unknown> = {
      ...patch,
      status: args.status ?? 'ok',
      step: 'done',
      inputs: args.inputs ?? doc.inputs,
      outputs: nextOutputs,
    };
    if (nextImageUrl) topLevelPatch.imageUrl = nextImageUrl;
    if (nextOutputRefs) topLevelPatch.outputRefs = nextOutputRefs;

    await ctx.db.patch(doc._id as any, {
      ...topLevelPatch,
    });
  },
});

export const fail = mutationGeneric({
  args: {
    clientRunId: v.string(),
    error: v.string(),
    httpStatus: v.optional(v.number()),
    finishedAt: v.number(),
  },
  handler: async (ctx, args) => {
    const doc = await findByClientId(ctx, args.clientRunId);
    if (!doc) return;
    await ctx.db.patch(doc._id as any, {
      status: 'error',
      step: 'done',
      error: args.error,
      httpStatus: args.httpStatus,
      finishedAt: args.finishedAt,
    });
  },
});
